// A debounce function delays invoking the given function until after wait milliseconds have elapsed since the last time it was invoked.
function debounce(func, wait) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(this, args), wait);
  };
}

// Example usage:
const log = debounce(() => console.log('Called after 500ms of inactivity'), 500);
window.addEventListener('resize', log);
